namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Fluffy Pancakes", Category = "Breakfast", Description = "Light and fluffy pancakes perfect for a weekend morning.", Ingredients = ["2 cups flour", "2 tbsp sugar", "2 tsp baking powder", "1 cup milk", "2 eggs", "3 tbsp melted butter"], Steps = ["Mix dry ingredients together.", "Whisk wet ingredients separately.", "Combine wet and dry ingredients until just mixed.", "Cook on a greased griddle until bubbles form, then flip."] },
            new() { Id = 2, Title = "Avocado Toast", Category = "Breakfast", Description = "Simple, healthy, and delicious avocado toast.", Ingredients = ["2 slices sourdough bread", "1 ripe avocado", "Salt and pepper", "Red pepper flakes", "Lemon juice"], Steps = ["Toast the bread until golden.", "Mash avocado with salt, pepper, and lemon juice.", "Spread on toast and top with red pepper flakes."] },
            new() { Id = 3, Title = "Classic BLT Sandwich", Category = "Lunch", Description = "A timeless bacon, lettuce, and tomato sandwich.", Ingredients = ["4 slices bacon", "2 slices bread", "Lettuce leaves", "2 tomato slices", "Mayonnaise"], Steps = ["Cook bacon until crispy.", "Toast the bread.", "Spread mayo on both slices.", "Layer lettuce, tomato, and bacon. Close and serve."] },
            new() { Id = 4, Title = "Caesar Salad", Category = "Lunch", Description = "Crisp romaine with creamy Caesar dressing and croutons.", Ingredients = ["1 head romaine lettuce", "1/2 cup Caesar dressing", "1/4 cup parmesan cheese", "1 cup croutons"], Steps = ["Wash and chop romaine lettuce.", "Toss with Caesar dressing.", "Top with parmesan cheese and croutons."] },
            new() { Id = 5, Title = "Grilled Chicken Wrap", Category = "Lunch", Description = "A protein-packed wrap with grilled chicken and veggies.", Ingredients = ["1 grilled chicken breast", "1 large tortilla", "Lettuce", "Tomato", "Ranch dressing"], Steps = ["Slice grilled chicken.", "Lay tortilla flat, add lettuce and tomato.", "Add chicken and drizzle with ranch.", "Roll tightly and slice in half."] },
            new() { Id = 6, Title = "Spaghetti Bolognese", Category = "Dinner", Description = "Rich and hearty Italian meat sauce over spaghetti.", Ingredients = ["400g spaghetti", "500g ground beef", "1 onion diced", "2 cloves garlic", "800ml crushed tomatoes", "2 tbsp tomato paste", "Italian seasoning"], Steps = ["Cook spaghetti according to package directions.", "Brown ground beef with onion and garlic.", "Add crushed tomatoes, tomato paste, and seasoning.", "Simmer for 20 minutes. Serve over pasta."] },
            new() { Id = 7, Title = "Lemon Herb Salmon", Category = "Dinner", Description = "Baked salmon with bright lemon and fresh herbs.", Ingredients = ["4 salmon fillets", "2 lemons", "Fresh dill", "Olive oil", "Salt and pepper", "Garlic"], Steps = ["Preheat oven to 400°F (200°C).", "Place salmon on a baking sheet lined with foil.", "Drizzle with olive oil, season with salt, pepper, and garlic.", "Top with lemon slices and dill. Bake 12-15 minutes."] },
            new() { Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts", Description = "Decadent individual cakes with a molten chocolate center.", Ingredients = ["200g dark chocolate", "100g butter", "2 eggs", "2 egg yolks", "50g sugar", "2 tbsp flour"], Steps = ["Melt chocolate and butter together.", "Whisk eggs, yolks, and sugar until thick.", "Fold chocolate mixture into eggs, then fold in flour.", "Pour into greased ramekins and bake at 425°F for 12 minutes."] },
            new() { Id = 9, Title = "Classic Cheesecake", Category = "Desserts", Description = "Creamy New York-style cheesecake with a graham cracker crust.", Ingredients = ["2 cups graham cracker crumbs", "500g cream cheese", "3/4 cup sugar", "3 eggs", "1 cup sour cream", "1 tsp vanilla"], Steps = ["Mix graham cracker crumbs with melted butter and press into pan.", "Beat cream cheese and sugar until smooth.", "Add eggs one at a time, then sour cream and vanilla.", "Pour over crust and bake at 325°F for 55 minutes."] },
            new() { Id = 10, Title = "Berry Smoothie Bowl", Category = "Breakfast", Description = "A thick and refreshing smoothie bowl topped with fresh fruit.", Ingredients = ["1 cup frozen mixed berries", "1 banana", "1/2 cup yogurt", "Granola", "Fresh berries for topping", "Honey"], Steps = ["Blend frozen berries, banana, and yogurt until thick.", "Pour into a bowl.", "Top with granola, fresh berries, and a drizzle of honey."] },
        };
        _nextId = 11;
    }

    public List<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().ToList();
        }
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetRecipeById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        lock (_lock)
        {
            recipe.Id = _nextId++;
            _recipes.Add(recipe);
        }
    }

    public void RateRecipe(int id, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == id);
            if (recipe is not null && stars >= 1 && stars <= 5)
            {
                var totalStars = recipe.AverageRating * recipe.RatingCount;
                recipe.RatingCount++;
                recipe.AverageRating = (totalStars + stars) / recipe.RatingCount;
            }
        }
    }
}

