        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" />
            <ValidationMessage For="() => _model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a Category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Description</label>
            <InputTextArea id="description" class="form-control" @bind-Value="_model.Description" rows="2" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" @bind-Value="_model.Ingredients" rows="5" />
            <ValidationMessage For="() => _model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" @bind-Value="_model.Steps" rows="5" />
            <ValidationMessage For="() => _model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
